INSERT INTO `project_architecture_notes` VALUES (1,'Integrations Enhance Guild CMS; They Do Not Define It','Guild CMS should remain the platform. phpBB, AWStats, Discord, Steam, OAuth, GeoIP, and future services should be providers or plugins that enhance the platform without becoming hard dependencies.','Principles','active',10,'2026-06-29 01:53:22','2026-06-29 02:18:30'),(2,'Site Manager Architecture','The database should become the source of truth for site registry data. The filesystem should contain scaffolded wrappers and reusable modules. Admin should orchestrate site creation, archiving, restoring, and validation.','Platform','active',20,'2026-06-29 01:53:22',NULL),(3,'Engineering Governance','Beginning with Phase 4.3, the Guild CMS Engineering Library becomes the authoritative public source for architecture standards, engineering principles, coding standards, security standards, developer guidance, and Architecture Decision Records.','Phase 4.3 Architecture','active',430,'2026-06-29 19:17:10',NULL),(4,'Engineering Publications Canonical Source','Engineering Library document bodies are published on the public Guild CMS website. The Development Center tracks publication IDs, statuses, versions, phases, and public links, but does not duplicate document content.','Phase 4.3 Architecture','active',431,'2026-06-29 19:55:15',NULL),(5,'User Experience and Educational Design Principle','Guild CMS should be educational, professional, modern, and accessible. User-facing workflows should explain before asking, teach instead of assuming, support safe recovery, and leave administrators more confident than when they began.','Product Experience','active',441,'2026-06-30 14:40:45',NULL),(6,'Installer Setup Detection Boundary','Guild CMS must not fail with PHP or database errors when a new installable tree has not been configured. The front controller detects missing or placeholder configuration and renders an educational setup-required page that links to the installer. The installer creates includes/config.inc.php during the install phase; completed configuration is installation-specific and should not be treated as reusable project source.','Installer','active',440,'2026-06-30 15:16:23',NULL),(7,'Installer Certification Framework','Guild CMS installer work is validated through a certification framework that distinguishes compatible, supported, and certified runtimes; certifies environments rather than paid hosting panels; and requires both technical validation and user-experience validation for installer releases.','Phase 4.4 Architecture','active',446,'2026-06-30 16:52:08',NULL),(8,'Development and Release Standard','Guild CMS packages follow GCMS-ENG-013: build against the authoritative baseline, modify actual source files, preserve admin/guildcms/devsite layout, include schema-compatible SQL, include release documentation and a package manifest, validate PHP syntax, and package only changed files without extra nesting.','Release Engineering','active',447,'2026-06-30 17:26:03',NULL),(9,'Installer Platform Intelligence','The Guild CMS installer detects the operating system, package manager family, web server, PHP runtime, database drivers, filesystem readiness, HTTPS status, SELinux, and AppArmor before later installer steps rely on environment-specific guidance. Detection is read-only and stored in installer session state.','Installer','active',448,'2026-06-30 18:01:37',NULL);
