INSERT INTO `project_changelog_entries` VALUES (1,'2026-06-29','Completed Phase 4.1 Codebase Modernization','Completed framework and subsystem modernization. Active direct superglobal usage was reduced to zero. Audit findings were reduced from 78 to 21. Reviewed shared pages, AC, AO, AO extras, TSW, WoW, CoD, CoH, EVE, FO76, layout framework, and main site sidebars.','4.1','milestone',1,NULL,NULL,'2026-06-29 01:53:22','2026-06-29 02:35:24'),(2,'2026-06-29','Started Development Center','Added roadmap/changelog/ideas/architecture schema and first admin dashboard for tracking Guild CMS development inside the site itself.','4.1K','session',1,NULL,NULL,'2026-06-29 01:53:22','2026-06-29 02:35:24'),(3,'2026-06-29','Development Center roadmap updated for Phase 4.2','Marked Phase 4.1 complete, set Phase 4.2 Security Hardening as the current phase, and revised the post-4.2 roadmap so Phase 4.3 is Installation & Bootstrap System, Phase 4.4 is Plugin Architecture, and Phase 4.5 is Admin Modernization.','4.2','milestone',0,0,'System','2026-06-29 13:46:02',NULL),(4,'2026-06-15','Web Site Revamp','TheRegs.org is long in the tooth we need to improve the entire site.  \r\n\r\nCurrently news is posted by phpBB but what if that project ever closed down?  How would we support the site?\r\n\r\nAll site pages and items need to be reviewed and cleaned up for current PHP standards.  ','0.0','session',1,2,'Alan Carr','2026-06-15 14:53:47','2026-06-29 17:33:37'),(5,'2026-06-29','Development Center v0.7 live roadmap dashboard','Updated the Development Center into a live engineering dashboard. The current phase checklist now comes from roadmap item data, Phase 4.2 security progress reflects completed/in-progress/planned work, and future phases are seeded with planned checklist items and mandatory security review gates.','4.1K','milestone',0,0,'System','2026-06-29 15:07:55',NULL),(8,'2026-06-29','Development Center v0.8 - Phase 4.2 Finalization','Phase 4.2 Security Hardening entered final review. Completed work includes security headers, cookie/session audit, CSRF audit, CSP inventory and Report-Only deployment, upload/file security audit, filesystem and permissions audit, legacy phpBB Gallery cleanup, legacy 777 permission cleanup, and Gallery upload hardening. Remaining work: final Phase 4.2 security review and sign-off.','4.2','milestone',0,0,'System','2026-06-29 16:11:25',NULL),(9,'2026-06-29','Security Hardening Enters Final Review','The Guild CMS Security Hardening phase is nearing completion. Work completed includes centralized application security headers, Content-Security-Policy Report-Only deployment, cookie/session and CSRF audits, upload/file security review, filesystem permission cleanup, legacy phpBB Gallery cleanup, and Gallery upload hardening. Final Phase 4.2 review is underway before moving to Phase 4.3: Installation & Bootstrap System.','4.2','milestone',1,0,'System','2026-06-29 16:11:25',NULL),(10,'2026-06-29','Phase 4.2 Complete','Completed Security Hardening. Final Security Review passed. Transitioned project to Phase 4.3 Installation & Bootstrap System.','4.2','milestone',1,0,'System','2026-06-29 17:23:04',NULL),(11,'2026-06-29','Phase 4.2 Security Hardening Complete','Phase 4.2 Security Hardening has been completed. The Guild CMS now has a documented security baseline including centralized application-layer security headers, Content-Security-Policy Report-Only, cookie and session audit, CSRF audit, upload and file security audit, filesystem permission cleanup, gallery upload hardening, legacy cleanup, and final security review. Development now moves to Phase 4.3: Installation & Bootstrap System.','4.2','milestone',1,0,'System','2026-06-29 17:29:11',NULL),(12,'2026-06-29','Phase 4.3 Installation & Bootstrap System Begins','With Security Hardening complete, The Guild CMS begins Phase 4.3. This phase focuses on the installation and bootstrap system: requirements checks, configuration generation, database setup, first-run setup, installer safety, and the path toward making the CMS portable beyond the flagship TheRegs.org installation.','4.3','milestone',1,0,'System','2026-06-29 17:29:11',NULL),(13,'2026-06-29','Package 4.3.0-1 - Development Center Realignment','Guild CMS enters Phase 4.3 - Engineering Foundation & Governance. The Development Center roadmap has been realigned, Phase 4.2 is marked complete, and the Engineering Library is introduced as the future public home for architecture, standards, governance, and engineering documentation.','4.3','release',0,0,'System','2026-06-29 19:17:10',NULL),(14,'2026-06-29','Public site prepared for Engineering Library','Public navigation, footer resources, roadmap text, documentation links, Engineering Library landing page, Founder\'s Note, and placeholder volume pages were added for Phase 4.3.','4.3.0-2','session',1,NULL,NULL,'2026-06-29 19:36:44',NULL),(15,'2026-06-29','Engineering Library publication framework established','The Engineering Library now uses a formal public publication model with stable identifiers, shared metadata, library navigation, breadcrumbs, the published Founder\'s Note, and reserved volume pages for future engineering standards.','4.3.0-3','session',1,NULL,NULL,'2026-06-29 19:45:43',NULL),(16,'2026-06-29','Package 4.3.0-3a - Development Center Publication Links','The Development Center now tracks Engineering Library publications as metadata and links to the canonical public documents on https://guildcms.theregs.org/engineering/. Document bodies remain on the public Guild CMS site to avoid duplicate sources of truth.','4.3','release',0,0,'System','2026-06-29 19:55:15',NULL),(17,'2026-06-29','GCMS-ENG-001 - The Guild CMS Constitution published','Published GCMS-ENG-001 as the first official Constitution publication in the Guild CMS Engineering Library. Volume I is now marked Published, the Development Center tracks the publication metadata, and the public site contains the authoritative document body.','4.3.0-4','session',1,NULL,NULL,'2026-06-29 20:35:31',NULL),(18,'2026-06-29','GCMS-ENG-003 Engineering Principles published','Published GCMS-ENG-003 Engineering Principles as Volume III of the Guild CMS Engineering Library. The Development Center now tracks the publication as published and links to the public Engineering Library as the authoritative source.','4.3.0-5','session',1,NULL,NULL,'2026-06-29 20:51:27',NULL),(19,'2026-06-29','GCMS-ENG-004 Architecture Standards published','Published GCMS-ENG-004 Architecture Standards as Volume IV of the Guild CMS Engineering Library. The Development Center now tracks the publication as published and links to the public Engineering Library as the authoritative source.','4.3.0-6','session',1,NULL,NULL,'2026-06-29 20:58:00',NULL),(20,'2026-06-29','GCMS-ENG-005 Developer Handbook published','Published GCMS-ENG-005 Developer Handbook as Volume V of the Guild CMS Engineering Library. The Development Center now tracks the publication as published and links to the public Engineering Library as the authoritative source.','4.3.0-7','session',1,NULL,NULL,'2026-06-29 21:12:55',NULL),(21,'2026-06-29','GCMS-ENG-006 Contribution Guide published','Published GCMS-ENG-006 Contribution Guide as Volume VI of the Guild CMS Engineering Library. The Development Center now tracks the publication as published and links to the public Engineering Library as the authoritative source.','4.3.0-8','session',1,NULL,NULL,'2026-06-29 21:28:36',NULL),(22,'2026-06-29','GCMS-ENG-007 Coding Standards published','Published GCMS-ENG-007 Coding Standards as Volume VII of the Guild CMS Engineering Library. The Development Center now tracks the publication as published and links to the public Engineering Library as the authoritative source.','4.3.0-8','session',1,NULL,NULL,'2026-06-29 21:41:07',NULL),(23,'2026-06-29','GCMS-ENG-008 Security Standards published','Published GCMS-ENG-008 as the official Security Standards publication for Guild CMS. The publication defines required security practices for validation, escaping, CSRF, authentication, authorization, SQL, uploads, sessions, cookies, security headers, logging, privacy, dependencies, release security review, and security defect handling.','4.3.0-9','release',1,NULL,NULL,'2026-06-29 21:46:49',NULL),(24,'2026-06-29','GCMS-ENG-009 Architecture Decision Records published','Published GCMS-ENG-009 as the official Architecture Decision Records publication for Guild CMS. The publication defines the ADR lifecycle, numbering, review process, standard format, and the first foundational ADRs covering the public Engineering Library, Development Center/public site separation, provider-based architecture, incremental release packages, and the engineering publication system.','4.3.0-10','release',1,NULL,NULL,'2026-06-29 21:54:06',NULL),(25,'2026-06-29','GCMS-ENG-010 Engineering Roadmap and Publication Framework published','Published GCMS-ENG-010 as the Engineering Roadmap and Publication Framework for the Guild CMS Engineering Library. The publication defines the publication lifecycle, numbering model, versioning rules, review process, future volumes, maintenance requirements, and marks Volume I of the Engineering Library as complete.','4.3.0-11','release',1,NULL,NULL,'2026-06-29 21:59:23',NULL),(26,'2026-06-29','Engineering Library Volume I completed','Completed the Volume I audit for the Guild CMS Engineering Library. GCMS-ENG-000 through GCMS-ENG-010 are now published as the foundational engineering publication set covering governance, constitution, vision, principles, architecture, developer workflow, contributions, coding, security, ADRs, and publication framework.','4.3.0-12','milestone',1,NULL,NULL,'2026-06-29 22:06:08',NULL),(27,'2026-06-30','Package 4.3.0-13 Phase Realignment Final','Phase 4.3 has been closed as Engineering Foundation & Governance. Installer and bootstrap milestones were moved into Phase 4.4 so the next phase begins from a clean Installation & Bootstrap System roadmap.','4.3.0-13','milestone',1,0,'Guild CMS','2026-06-30 11:34:02',NULL),(28,'2026-06-30','Package 4.4.0-1 - Installation Architecture','Opened Phase 4.4 - Installation & Bootstrap System. Defined the Guild CMS installer boundary, bootstrap stage model, package sequence, and security expectations. Updated roadmap metadata and public project pages.','4.4','release',1,0,'System','2026-06-30 12:11:21',NULL),(29,'2026-06-30','GCMS-ENG-011 User Experience & Educational Design Principles Published','Published GCMS-ENG-011 as the Guild CMS Engineering Library standard for user experience and educational design. The publication defines explain-before-asking, teach-don\'t-assume, educational installer design, confidence-building workflows, and recovery-oriented error guidance for Phase 4.4 and future user-facing work.','4.4.0-2','milestone',1,0,'Guild CMS','2026-06-30 13:32:12',NULL),(31,'2026-06-30','Installer Framework','Added the initial devsite /install/ framework and established devsite as the installable Guild CMS product tree. Updated Phase 4.4 roadmap tracking using schema-valid enum values.','4.4.0-2','milestone',1,0,'Guild CMS','2026-06-30 13:54:12','2026-06-30 13:54:12'),(32,'2026-06-30','Phase 4.4 Installer Roadmap Refined','Refined the Phase 4.4 installer roadmap around the devsite installable product tree. The sequence now moves from installation architecture and installer framework into setup detection, product separation, installer expansion, requirements validation, database bootstrap, installation completion, and installer security review. Phase 4.5 remains Data Normalization & Governance and Phase 4.6 remains Upgrade & Migration Framework.','4.4.0-2b','milestone',1,0,'Guild CMS','2026-06-30 13:54:12','2026-06-30 13:54:12'),(33,'2026-06-30','GCMS-ENG-011 User Experience & Educational Design Principles Published','Published GCMS-ENG-011 as the Guild CMS Engineering Library standard for product experience and educational design. The publication defines explain-before-asking, teach-don\'t-assume, system readiness, installer navigation, save/resume, cancel safety, meaningful progress, contextual help, recovery-oriented errors, accessibility, and the principle that the installer introduces the Guild CMS experience.','4.4.0-3','milestone',1,0,'Guild CMS','2026-06-30 14:40:45',NULL),(34,'2026-06-30','Package 4.4.0-4 First Installer Published','Introduced the first Guild CMS installer experience in devsite, including setup detection, a setup-required landing page, config sample reference, expanded installer step model, required system readiness checks, recommended feature checks, progress display, save and cancel controls, and public/admin documentation updates.','4.4','milestone',1,0,'Guild CMS','2026-06-30 15:16:23',NULL),(35,'2026-06-30','Package 4.4.0-5 - System Readiness Check','Implemented the first testable installer validation step. Guild CMS now separates required server readiness checks from recommended feature checks, explains why each item matters, provides corrective guidance, and blocks continuation only when a required runtime capability is missing.','4.4.0-5','release',1,0,'Guild CMS','2026-06-30 15:38:18',NULL),(36,'2026-06-30','GCMS-ENG-012 Installer Testing & Certification Framework Published','Published GCMS-ENG-012 to define installer testing philosophy, PHP runtime support policy, certification environments, base and perfect expectations, failure recovery tests, UX validation, security checks, and release certification standards for Phase 4.4.','4.4.0-6','milestone',1,0,'Guild CMS','2026-06-30 16:52:08',NULL),(37,'2026-06-30','GCMS-ENG-013 Development & Release Standard Published','Published GCMS-ENG-013 to define the official Guild CMS development and release standard, including package layout, changed-file packaging, SQL migration rules, roadmap semantics, validation gates, release documentation, package manifests, and Git baseline policy.','4.4.0-7','milestone',1,0,'Guild CMS','2026-06-30 17:26:03',NULL),(38,'2026-06-30','Installer Environment Detection Added','Added platform intelligence to the Guild CMS installer so it can detect the operating system, package manager family, web server, PHP runtime, database drivers, filesystem readiness, HTTPS status, SELinux, and AppArmor before later setup steps use that information for guidance.','4.4.0-8','release',1,0,'Guild CMS','2026-06-30 18:01:37',NULL),(39,'2026-06-30','Environment Detection Usability Enhanced','Refined the installer Environment Detection page to explain results before displaying technical details. Added effective PHP user/group, document root, includes directory ownership, permissions, php.ini information, progressive disclosure, and permission guidance.','4.4.0-8a','release',1,0,'Guild CMS','2026-06-30 18:28:22',NULL),(40,'2026-07-01','Package 4.4.0-9 - Installer Certification Milestone 1 Published','Published Installer Certification Milestone 1 for Guild CMS Installer 4.4.0-8a. Certification reports now document Rocky Linux 9.8 with Virtualmin, Rocky Linux 9.8 Minimal, AlmaLinux 9.8 Minimal, Ubuntu 24 Minimal, and Debian 12 Minimal. Phase 4.4 is complete and Phase 4.5 - Core Installation Experience is ready to begin.','4.4.0-9','milestone',1,0,'Guild CMS','2026-07-01 23:26:37',NULL),(41,'2026-07-01','Package 4.4.0-10 - Phase Roadmap Realignment','Phase 4.4 has been realigned to represent the complete installer lifecycle. Configuration generation, requirements validation, database bootstrap, database initialization, administrator account creation, first-run site configuration, plugin manifest format, plugin discovery, hook/event system, site bootstrap, and installation locking/recovery now remain in Phase 4.4. Phase 4.5 is restored as Data Normalization & Governance. No new installer runtime functionality was introduced in this package.','4.4.0-10','milestone',1,0,'Guild CMS','2026-07-01 23:53:30',NULL);
