INSERT INTO `project_roadmap_phases` VALUES (1,'1','Phase 1 - Foundation','Core site rebuild foundation and early CMS/admin groundwork.','complete',100,10,NULL,'2026-06-29','2026-06-29 01:53:22',NULL,1),(2,'2','Phase 2 - Administration Framework','Admin structure, CRUD sections, pagination, audit logging, and management pages.','complete',100,20,NULL,'2026-06-29','2026-06-29 01:53:22',NULL,1),(3,'3A','Phase 3A - Shared Layout','Shared layout framework and sidebar migration.','complete',100,30,NULL,'2026-06-29','2026-06-29 01:53:22',NULL,1),(4,'3B','Phase 3B - Navigation Manager','Database-driven navigation manager, importer, drag/drop, publishing, and publish history.','complete',100,31,NULL,'2026-06-29','2026-06-29 01:53:22','2026-06-29 13:51:14',1),(5,'3C','Phase 3C - Content Rendering Engine','Article renderer with plain text, BBCode, quotes, lists, tables, and media support.','complete',100,32,NULL,'2026-06-29','2026-06-29 01:53:22','2026-06-29 13:51:14',1),(6,'4.1','Phase 4.1 - Security Foundation','Security foundation work completed before Phase 4.2 hardening.','complete',100,410,NULL,'2026-06-29','2026-06-29 01:53:22','2026-06-30 12:13:53',1),(7,'4.1K','Phase 4.1 - Security Foundation','Security foundation work completed before Phase 4.2 hardening.','archived',100,9999,NULL,'2026-06-29','2026-06-29 01:53:22','2026-06-29 20:06:19',0),(8,'4.2','Phase 4.2 - Security Hardening','Security hardening is in final review after completing security headers, cookie/session review, CSRF review, CSP Report-Only rollout, upload/file review, filesystem permission cleanup, and Gallery upload hardening.','complete',100,420,'2026-06-29','2026-06-29','2026-06-29 01:53:22','2026-06-30 12:13:53',1),(11,'4.3','Phase 4.3 - Engineering Foundation & Governance','Engineering Foundation & Governance is complete. Phase 4.3 delivered the Engineering Library Volume I publication set, governance model, engineering standards, Architecture Decision Records, contribution workflow, coding standards, security standards, and publication framework.','complete',100,430,'2026-06-29','2026-06-30','2026-06-29 13:46:02','2026-06-30 13:54:12',1),(12,'4.4','Phase 4.4 - Installation & Bootstrap System','Phase 4.4 owns the complete Guild CMS installer lifecycle: installer architecture, setup detection, product separation, platform intelligence, requirements validation, configuration generation, database bootstrap, database initialization, administrator account creation, first-run site configuration, plugin bootstrap responsibilities, site bootstrap, installer locking, recovery, certification, and security review.','in_progress',75,440,'2026-06-30',NULL,'2026-06-29 13:46:02','2026-07-01 23:53:30',1),(13,'4.6','Phase 4.6 - Upgrade & Migration Framework','Upgrade workflow, migration runner, versioned schema changes, and safe platform update procedures.','planned',0,460,NULL,NULL,'2026-06-29 13:46:02','2026-07-01 23:53:30',1),(14,'5.0','Phase 5.0 - Plugin SDK & Extension Framework','Plugin SDK, extension framework, hooks, events, and package architecture.','planned',0,500,NULL,NULL,'2026-06-29 13:46:02','2026-06-30 12:13:53',1),(15,'5.1','Phase 5.1 - Theme Engine & Template System','Theme engine, template system, theme inheritance, and presentation customization framework.','planned',0,510,NULL,NULL,'2026-06-29 13:46:02','2026-06-30 12:13:53',1),(16,'5.2','Phase 5.2 - CLI & Developer Tools','Command-line tooling, developer utilities, scaffolding, maintenance commands, and development workflows.','planned',0,520,NULL,NULL,'2026-06-29 13:46:02','2026-06-30 12:13:53',1),(17,'5.3','Phase 5.3 - REST API & Developer Services','REST API, developer services, API documentation, service contracts, and integration endpoints.','planned',0,530,NULL,NULL,'2026-06-29 13:46:02','2026-06-30 12:13:53',1),(18,'5.6','Phase 5.6 - Release Readiness & Final Security Review','Complete the final platform-wide security audit, release readiness review, documentation review, installer validation, upgrade validation, and release candidate sign-off before public release.','planned',0,560,NULL,NULL,'2026-06-29 13:46:02','2026-06-30 13:54:12',1),(19,'6.0','Phase 6.0 - Public Release','Public release of The Guild CMS after release readiness and final security review are complete.','planned',0,600,NULL,NULL,'2026-06-29 13:46:02','2026-06-30 13:54:12',1),(20,'5.4','Phase 5.4 - Provider Framework Expansion','Provider framework expansion for additional integrations and configurable service providers.','planned',0,540,NULL,NULL,'2026-06-29 19:17:10','2026-06-30 12:13:53',1),(21,'5.5','Phase 5.5 - Native Authentication System','Native authentication system for standalone Guild CMS installations and non-phpBB deployments.','planned',0,550,NULL,NULL,'2026-06-29 19:17:10','2026-06-30 12:13:53',1),(22,'4.5','Phase 4.5 - Data Normalization & Governance','Normalize project data, document database schemas and enum values, establish database governance rules, and prepare reliable migrations after the installer lifecycle is complete.','planned',0,450,NULL,NULL,'2026-06-30 13:10:51','2026-07-01 23:53:30',1);
