INSERT INTO `project_vision_notes` VALUES (1,'The Guild CMS Platform Vision','Guild CMS is evolving from a legacy gaming community website into a modular PHP community management platform. It should manage sites, content, navigation, media, analytics, users, plugins, and integrations through a consistent admin framework.','Vision',10,'active','2026-06-29 02:14:51','2026-06-29 02:22:30',1),(2,'Architecture Principle: Integrations Enhance, Not Define','phpBB, AWStats, Discord, Steam, OAuth, GeoIP, and future services should enhance The Guild CMS as providers or plugins. The Guild CMS should remain functional even if an integration is unavailable.','Principles',20,'active','2026-06-29 02:14:51','2026-06-29 02:22:22',1),(3,'Development Center Purpose','The Development Center is the project management hub for The Guild CMS itself. It tracks roadmap phases, development sessions, changelog entries, ideas, project health, architecture notes, and long-term product direction.','Development Center',30,'active','2026-06-29 02:14:51','2026-06-29 02:22:41',1),(4,'Security-First Engineering','The Guild CMS now treats security review as a phase completion gate. Each major development phase concludes with a security review, documented findings, remediation where needed, Development Center updates, and public roadmap updates. Before public release, Phase 6.0 will perform a final platform-wide security and release-readiness review.','Engineering Standards',35,'active','2026-06-29 17:29:11',NULL,1);
